#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d",&N,&Q);
        long long *row = (long long*)calloc(N,sizeof(long long));
        long long *col = (long long*)calloc(N,sizeof(long long));
        char op[10];
        for(int i=0;i<Q;i++){
            int idx; long long val; scanf("%s %d %lld",op,&idx,&val);
            if(op[0]=='R') row[idx-1]+=val; else col[idx-1]+=val;
        }
        long long maxRow=0, maxCol=0;
        for(int i=0;i<N;i++) if(row[i]>maxRow) maxRow=row[i];
        for(int i=0;i<N;i++) if(col[i]>maxCol) maxCol=col[i];
        printf("%lld\n", maxRow+maxCol);
        free(row); free(col);
    }
    return 0;
}

